import java.util.concurrent.atomic.AtomicInteger;

use std::sync::atomic::{AtomicI32, Ordering};

struct ThreadCounter {
    count: AtomicI32,
}

impl ThreadCounter {
    fn increment(&self) {
        self.count.fetch_add(1, Ordering::SeqCst);
    }
}
